/**
 * Prepare structured context for the LLM email generator.
 * Includes country-specific value props so the email reads native, not templated.
 */

const lead = $input.item.json;

// Country-specific pain points / value props (Pemo's actual MENA messaging).
const COUNTRY_VALUE_PROPS = {
  AE: [
    "real-time spend visibility for fast-scaling SMEs",
    "multi-currency virtual cards (AED + USD/EUR for international ops)",
    "eliminate the shared-card chaos most Dubai/Abu Dhabi teams suffer with"
  ],
  SA: [
    "localized accounting & ZATCA-ready VAT export",
    "Arabic-first UI for finance teams",
    "instant SAR settlement via our neoleap (Alrajhi) partnership"
  ],
  EG: [
    "cost optimization under EGP volatility",
    "consolidate multi-bank expenses into a single dashboard",
    "simplified expense reporting that scales with hiring"
  ],
  // GCC + Other fallback
  default: [
    "real-time spend visibility for growing SMEs",
    "automated receipt capture and AI-powered categorization",
    "control over team spending without slowing down operations"
  ]
};

const valueProps = COUNTRY_VALUE_PROPS[lead.country] || COUNTRY_VALUE_PROPS.default;

return {
  json: {
    ...lead,
    _email_context: {
      lead_first_name: (lead.contact_name || "").split(" ")[0] || "there",
      lead_full_name: lead.contact_name || "",
      company: lead.company_name || "",
      country: lead.country || "",
      industry: lead.industry || "",
      company_size: lead.company_size || "",
      tech_stack: (lead.tech_stack || []).join(", "),
      inbound_message: lead.raw_message || "",
      qualification_summary: lead.qualification_summary || "",
      language: lead.language || "en",
      country_value_props: valueProps,
      calendly_link: "https://calendly.com/kalinaadam75/pemo-demo",
      rep_name: lead._assignment?.rep_name || "the Pemo team",
      rep_email: lead._assignment?.rep_email || "team@pemo.io"
    }
  }
};

