/**
 * Parse the LLM email JSON. Defensive: LLMs sometimes wrap output in markdown
 * code fences or include preamble despite explicit instructions. Strip & retry.
 */

const lead = $('Build Email Context').item.json;
const ai = $input.item.json;

function extractContent(o) {
  if (!o) return "";
  // n8n OpenAI Responses API
  if (Array.isArray(o.output) && o.output[0]?.content) {
    const block = o.output[0].content.find((c) => c.type === "output_text" || typeof c.text === "string");
    if (block?.text) return block.text;
  }
  if (typeof o.text === "string") return o.text;
  if (o.message?.content) return o.message.content;
  if (o.choices?.[0]?.message?.content) return o.choices[0].message.content;
  return "";
}

let raw = extractContent(ai).trim();
// Strip markdown fences if present
raw = raw.replace(/^```(?:json)?\s*/i, "").replace(/```\s*$/, "").trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  // Fallback: extract subject + body from plain text shape
  const subjectMatch = raw.match(/subject[:\s"]*([^\n"]+)/i);
  const bodyMatch = raw.match(/body[:\s"]*([\s\S]+)/i);
  parsed = {
    subject: subjectMatch?.[1]?.trim() || "Pemo demo follow-up",
    body: bodyMatch?.[1]?.trim() || raw
  };
}

return {
  json: {
    ...lead,
    _outreach: {
      channel: "hot",
      subject: parsed.subject || "Pemo demo follow-up",
      body: parsed.body || "",
      to: lead.email,
      from_name: lead._email_context.rep_name,
      generated_at: new Date().toISOString()
    }
  }
};

